   392      private boolean flushNetOutBufferAndUpdateInterestOps() throws IOException {
   393          boolean flushedCompletely = flushNetOutBuffer();
   394          if (flushedCompletely) {
   395              transportLayer.removeInterestOps(SelectionKey.OP_WRITE);
   396              if (pendingSaslState != null)
   397                  setSaslState(pendingSaslState, pendingException);
   398          } else
   399              transportLayer.addInterestOps(SelectionKey.OP_WRITE);
   400          return flushedCompletely;
   401      }
