   180          @Override
   181          public SaslServer createSaslServer(String mechanism, String protocol, String serverName, Map<String, ?> props, CallbackHandler cbh)
   182              throws SaslException {
   183
   184              if (!PLAIN_MECHANISM.equals(mechanism))
   185                  throw new SaslException(String.format("Mechanism \'%s\' is not supported. Only PLAIN is supported.", mechanism));
   186
   187              return new PlainSaslServer(cbh);
   188          }
   189
   190          @Override
   191          public String[] getMechanismNames(Map<String, ?> props) {
   192              if (props == null) return new String[]{PLAIN_MECHANISM};
   193              String noPlainText = (String) props.get(Sasl.POLICY_NOPLAINTEXT);
   194              if ("true".equals(noPlainText))
   195                  return new String[]{};
   196              else
   197                  return new String[]{PLAIN_MECHANISM};
   198          }
   199      }
   200  }

