   222      public static String[] mechanismNamesCompatibleWithPolicy(Map<String, ?> props) {
   223          return props != null && "true".equals(String.valueOf(props.get(Sasl.POLICY_NOPLAINTEXT))) ? new String[] {}
   224                  : new String[] {OAuthBearerLoginModule.OAUTHBEARER_MECHANISM};
   225      }
