    18
    19  import java.io.IOException;
    20  import java.util.ArrayList;
    21  import java.util.Collections;
    22  import java.util.List;
    23  import java.util.regex.Matcher;
    24  import java.util.regex.Pattern;
    25
    26  /**
    27   * This class implements parsing and handling of Kerberos principal names. In
    28   * particular, it splits them apart and translates them down into local
    29   * operating system names.
    30   */
    31  public class KerberosShortNamer {
    32
    33      /**
    34       * A pattern for parsing a auth_to_local rule.
    35       */
    36      private static final Pattern RULE_PARSER = Pattern.compile("((DEFAULT)|((RULE:\\[(\\d*):([^\\]]*)](\\(([^)]*)\\))?(s/([^/]*)/([^/]*)/(g)?)?/?(L|U)?)))");
    37
    38      /* Rules for the translation of the principal name into an operating system name */
    39      private final List<KerberosRule> principalToLocalRules;
    40
    41      public KerberosShortNamer(List<KerberosRule> principalToLocalRules) {
    42          this.principalToLocalRules = principalToLocalRules;
    43      }
    44
    45      public static KerberosShortNamer fromUnparsedRules(String defaultRealm, List<String> principalToLocalRules) {
    46          List<String> rules = principalToLocalRules == null ? Collections.singletonList("DEFAULT") : principalToLocalRules;
    47          return new KerberosShortNamer(parseRules(defaultRealm, rules));
    48      }
    49
    50      private static List<KerberosRule> parseRules(String defaultRealm, List<String> rules) {
    51          List<KerberosRule> result = new ArrayList<>();
    52          for (String rule : rules) {
    53              Matcher matcher = RULE_PARSER.matcher(rule);
    54              if (!matcher.lookingAt()) {
    55                  throw new IllegalArgumentException("Invalid rule: " + rule);
    56              }
    57              if (rule.length() != matcher.end())
    58                  throw new IllegalArgumentException("Invalid rule: `" + rule + "`, unmatched substring: `" + rule.substring(matcher.end()) + "`");
    59              if (matcher.group(2) != null) {
    60                  result.add(new KerberosRule(defaultRealm));
    61              } else {
    62                  result.add(new KerberosRule(defaultRealm,
    63                          Integer.parseInt(matcher.group(5)),
    64                          matcher.group(6),
    65                          matcher.group(8),
    66                          matcher.group(10),
    67                          matcher.group(11),
    68                          "g".equals(matcher.group(12)),
    69                          "L".equals(matcher.group(13)),
    70                          "U".equals(matcher.group(13))));
    71
    72              }
    73          }
    74          return result;
    75      }
    76
    77      /**
    78       * Get the translation of the principal name into an operating system
    79       * user name.
    80       * @return the short name
    81       * @throws IOException
    82       */
    83      public String shortName(KerberosName kerberosName) throws IOException {
    84          String[] params;
    85          if (kerberosName.hostName() == null) {
    86              // if it is already simple, just return it
    87              if (kerberosName.realm() == null)
    88                  return kerberosName.serviceName();
    89              params = new String[]{kerberosName.realm(), kerberosName.serviceName()};
    90          } else {
    91              params = new String[]{kerberosName.realm(), kerberosName.serviceName(), kerberosName.hostName()};
    92          }
    93          for (KerberosRule r : principalToLocalRules) {
    94              String result = r.apply(params);
    95              if (result != null)
    96                  return result;
    97          }
    98          throw new NoMatchingRule("No rules apply to " + kerberosName + ", rules " + principalToLocalRules);
    99      }
