    45  /**
    46   * Default implementation of {@link KafkaPrincipalBuilder} which provides basic support for
    47   * SSL authentication and SASL authentication. In the latter case, when GSSAPI is used, this
    48   * class applies {@link org.apache.kafka.common.security.kerberos.KerberosShortNamer} to transform
    49   * the name.
    50   *
    51   * NOTE: This is an internal class and can change without notice.
    52   */
    53  public class DefaultKafkaPrincipalBuilder implements KafkaPrincipalBuilder, KafkaPrincipalSerde {
    54      private final KerberosShortNamer kerberosShortNamer;
    55      private final SslPrincipalMapper sslPrincipalMapper;
    56
    57      /**
    58       * Construct a new instance.
    59       *
    60       * @param kerberosShortNamer Kerberos name rewrite rules or null if none have been configured
    61       * @param sslPrincipalMapper SSL Principal mapper or null if none have been configured
    62       */
    63      public DefaultKafkaPrincipalBuilder(KerberosShortNamer kerberosShortNamer, SslPrincipalMapper sslPrincipalMapper) {
    64          this.kerberosShortNamer = kerberosShortNamer;
    65          this.sslPrincipalMapper = sslPrincipalMapper;
    66      }
    67
    68      @Override
    69      public KafkaPrincipal build(AuthenticationContext context) {
    70          if (context instanceof PlaintextAuthenticationContext) {
    71              return KafkaPrincipal.ANONYMOUS;
    72          } else if (context instanceof SslAuthenticationContext) {
    73              SSLSession sslSession = ((SslAuthenticationContext) context).session();
    74              try {
    75                  return applySslPrincipalMapper(sslSession.getPeerPrincipal());
    76              } catch (SSLPeerUnverifiedException se) {
    77                  return KafkaPrincipal.ANONYMOUS;
    78              }
    79          } else if (context instanceof SaslAuthenticationContext) {
    80              SaslServer saslServer = ((SaslAuthenticationContext) context).server();
    81              if (SaslConfigs.GSSAPI_MECHANISM.equals(saslServer.getMechanismName()))
    82                  return applyKerberosShortNamer(saslServer.getAuthorizationID());
    83              else
    84                  return new KafkaPrincipal(KafkaPrincipal.USER_TYPE, saslServer.getAuthorizationID());
    85          } else {
    86              throw new IllegalArgumentException("Unhandled authentication context type: " + context.getClass().getName());
    87          }
    88      }
    89
    90      private KafkaPrincipal applyKerberosShortNamer(String authorizationId) {
    91          KerberosName kerberosName = KerberosName.parse(authorizationId);
    92          try {
    93              String shortName = kerberosShortNamer.shortName(kerberosName);
    94              return new KafkaPrincipal(KafkaPrincipal.USER_TYPE, shortName);
    95          } catch (IOException e) {
    96              throw new KafkaException("Failed to set name for '" + kerberosName +
    97                      "' based on Kerberos authentication rules.", e);
    98          }
    99      }
   100
   101      private KafkaPrincipal applySslPrincipalMapper(Principal principal) {
   102          try {
   103              if (!(principal instanceof X500Principal) || principal == KafkaPrincipal.ANONYMOUS) {
   104                  return new KafkaPrincipal(KafkaPrincipal.USER_TYPE, principal.getName());
   105              } else {
   106                  return new KafkaPrincipal(KafkaPrincipal.USER_TYPE, sslPrincipalMapper.getName(principal.getName()));
   107              }
   108          } catch (IOException e) {
   109              throw new KafkaException("Failed to map name for '" + principal.getName() +
   110                      "' based on SSL principal mapping rules.", e);
   111          }
   112      }
   113
   114      @Override
   115      public byte[] serialize(KafkaPrincipal principal) {
   116          DefaultPrincipalData data = new DefaultPrincipalData()
   117                                          .setType(principal.getPrincipalType())
   118                                          .setName(principal.getName())
   119                                          .setTokenAuthenticated(principal.tokenAuthenticated());
   120          return MessageUtil.toVersionPrefixedBytes(DefaultPrincipalData.HIGHEST_SUPPORTED_VERSION, data);
   121      }
   122
   123      @Override
   124      public KafkaPrincipal deserialize(byte[] bytes) {
   125          ByteBuffer buffer = ByteBuffer.wrap(bytes);
   126          short version = buffer.getShort();
   127          if (version < DefaultPrincipalData.LOWEST_SUPPORTED_VERSION || version > DefaultPrincipalData.HIGHEST_SUPPORTED_VERSION) {
   128              throw new SerializationException("Invalid principal data version " + version);
   129          }
   130
   131          DefaultPrincipalData data = new DefaultPrincipalData(new ByteBufferAccessor(buffer), version);
   132          return new KafkaPrincipal(data.type(), data.name(), data.tokenAuthenticated());
   133      }
   134  }

