   156              callbackHandler.handle(new Callback[] {callback});
   157          } catch (IOException | UnsupportedCallbackException e) {
   158              handleCallbackError(e);
   159          }
   160          OAuthBearerToken token = callback.token();
   161          if (token == null) {
   162              errorMessage = jsonErrorResponse(callback.errorStatus(), callback.errorScope(),
   163                      callback.errorOpenIDConfiguration());
   164              log.debug(errorMessage);
   165              return errorMessage.getBytes(StandardCharsets.UTF_8);
   166          }
   167          /*
   168           * We support the client specifying an authorization ID as per the SASL
   169           * specification, but it must match the principal name if it is specified.
   170           */
   171          if (!authorizationId.isEmpty() && !authorizationId.equals(token.principalName()))
   172              throw new SaslAuthenticationException(String.format(
   173                      "Authentication failed: Client requested an authorization id (%s) that is different from the token's principal name (%s)",
   174                      authorizationId, token.principalName()));
   175
   176          Map<String, String> validExtensions = processExtensions(token, extensions);
   177
   178          tokenForNegotiatedProperty = token;
   179          this.extensions = new SaslExtensions(validExtensions);
   180          complete = true;
   181          log.debug("Successfully authenticate User={}", token.principalName());
   182          return new byte[0];
   183      }
   184
   185      private Map<String, String> processExtensions(OAuthBearerToken token, SaslExtensions extensions) throws SaslException {
   186          OAuthBearerExtensionsValidatorCallback extensionsCallback = new OAuthBearerExtensionsValidatorCallback(token, extensions);
   187          try {
   188              callbackHandler.handle(new Callback[] {extensionsCallback});
   189          } catch (UnsupportedCallbackException e) {
   190              // backwards compatibility - no extensions will be added
   191          } catch (IOException e) {
   192              handleCallbackError(e);
   193          }
   194          if (!extensionsCallback.invalidExtensions().isEmpty()) {
   195              String errorMessage = String.format("Authentication failed: %d extensions are invalid! They are: %s",
   196                      extensionsCallback.invalidExtensions().size(),
   197                      Utils.mkString(extensionsCallback.invalidExtensions(), "", "", ": ", "; "));
   198              log.debug(errorMessage);
   199              throw new SaslAuthenticationException(errorMessage);
   200          }
   201
   202          return extensionsCallback.validatedExtensions();
   203      }
   204
   205      private static String jsonErrorResponse(String errorStatus, String errorScope, String errorOpenIDConfiguration) {
   206          String jsonErrorResponse = String.format("{\"status\":\"%s\"", errorStatus);
   207          if (errorScope != null)
   208              jsonErrorResponse = String.format("%s, \"scope\":\"%s\"", jsonErrorResponse, errorScope);
   209          if (errorOpenIDConfiguration != null)
   210              jsonErrorResponse = String.format("%s, \"openid-configuration\":\"%s\"", jsonErrorResponse,
   211                      errorOpenIDConfiguration);
   212          jsonErrorResponse = String.format("%s}", jsonErrorResponse);
   213          return jsonErrorResponse;
   214      }
   215
   216      private void handleCallbackError(Exception e) throws SaslException {
   217          String msg = String.format("%s: %s", INTERNAL_ERROR_ON_SERVER, e.getMessage());
   218          log.debug(msg, e);
   219          throw new SaslException(msg);
   220      }
