    50      public OAuthBearerClientInitialResponse(byte[] response) throws SaslException {
    51          String responseMsg = new String(response, StandardCharsets.UTF_8);
    52          Matcher matcher = CLIENT_INITIAL_RESPONSE_PATTERN.matcher(responseMsg);
    53          if (!matcher.matches())
    54              throw new SaslException("Invalid OAUTHBEARER client first message");
    55          String authzid = matcher.group("authzid");
    56          this.authorizationId = authzid == null ? "" : authzid;
    57          String kvPairs = matcher.group("kvpairs");
    58          Map<String, String> properties = Utils.parseMap(kvPairs, "=", SEPARATOR);
    59          String auth = properties.get(AUTH_KEY);
    60          if (auth == null)
    61              throw new SaslException("Invalid OAUTHBEARER client first message: 'auth' not specified");
    62          properties.remove(AUTH_KEY);
    63          SaslExtensions extensions = new SaslExtensions(properties);
    64          validateExtensions(extensions);
